const { cleanedUsers: salonUsers, report: cleaningReport } = cleanSalonUsers(rawSalonUsers);

async function runMigration(client) {
  console.log('📋 Creating salon_users table...');
  
  await client.query(`
    CREATE TABLE IF NOT EXISTS salon_users (
      id SERIAL PRIMARY KEY,
      salon_name VARCHAR(255) NOT NULL,
      phone_number VARCHAR(30),
      profiles INTEGER DEFAULT 0,
      first_mix_date VARCHAR(50),
      last_mix_date VARCHAR(50),
      monthly_trend VARCHAR(20) DEFAULT '-',
      version VARCHAR(10),
      state VARCHAR(100),
      city VARCHAR(100),
      links VARCHAR(255),
      summit TEXT DEFAULT '',
      instagram TEXT DEFAULT '',
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
  `);

  await client.query(`CREATE INDEX IF NOT EXISTS idx_salon_users_salon_name ON salon_users(salon_name);`);
  await client.query(`CREATE INDEX IF NOT EXISTS idx_salon_users_phone ON salon_users(phone_number);`);
  await client.query(`CREATE INDEX IF NOT EXISTS idx_salon_users_version ON salon_users(version);`);
  await client.query(`CREATE INDEX IF NOT EXISTS idx_salon_users_state ON salon_users(state);`);
  await client.query(`CREATE INDEX IF NOT EXISTS idx_salon_users_city ON salon_users(city);`);

  console.log('✅ Table and indexes created successfully');
}

async function importData(client) {
  console.log(`📊 Cleaning ${cleaningReport.rawCount} raw salon users...`);
  console.log(`   -> ${salonUsers.length} cleaned records`);
  console.log(`   -> ${cleaningReport.removedDuplicates} duplicate rows merged`);
  console.log(`   -> ${cleaningReport.normalizedPhones} phones normalized`);
  console.log(`   -> ${cleaningReport.normalizedStates} states normalized`);
  console.log(`   -> ${cleaningReport.normalizedCities} cities normalized`);
  console.log(`📥 Importing ${salonUsers.length} salon users...`);
  
  // Clear existing data
  await client.query('TRUNCATE TABLE salon_users RESTART IDENTITY CASCADE');
  
  // Insert in batches of 50
  const batchSize = 50;
  let inserted = 0;
  
  for (let i = 0; i < salonUsers.length; i += batchSize) {
    const batch = salonUsers.slice(i, i + batchSize);
    
    const values = [];
    const params = [];
    let paramIdx = 1;
    
    for (const user of batch) {
      values.push(`($${paramIdx}, $${paramIdx+1}, $${paramIdx+2}, $${paramIdx+3}, $${paramIdx+4}, $${paramIdx+5}, $${paramIdx+6}, $${paramIdx+7}, $${paramIdx+8}, $${paramIdx+9}, $${paramIdx+10}, $${paramIdx+11})`);
      params.push(
        user.salon_name,
        user.phone_number,
        user.profiles,
        user.first_mix_date,
        user.last_mix_date,
        user.monthly_trend,
        user.version,
        user.state || null,
        user.city || null,
        user.links || null,
        user.summit || '',
        user.instagram || ''
      );
      paramIdx += 12;
    }
    
    const query = `
      INSERT INTO salon_users (salon_name, phone_number, profiles, first_mix_date, last_mix_date, monthly_trend, version, state, city, links, summit, instagram)
      VALUES ${values.join(', ')}
    `;
    
    await client.query(query, params);
    inserted += batch.length;
    console.log(`✅ Imported ${inserted}/${salonUsers.length} records`);
  }
  
  // Show summary
  const summary = await client.query(`
    SELECT 
      COUNT(*) as total_records,
      COUNT(DISTINCT salon_name) as unique_salons,
      COUNT(DISTINCT phone_number) FILTER (WHERE phone_number IS NOT NULL AND phone_number != '') as unique_phones,
      COUNT(DISTINCT state) FILTER (WHERE state IS NOT NULL AND state != '') as countries,
      COUNT(DISTINCT city) FILTER (WHERE city IS NOT NULL AND city != '') as cities,
      SUM(profiles) as total_profiles,
      COUNT(*) FILTER (WHERE version = '1021') as on_latest_version
    FROM salon_users
  `);
  
  const s = summary.rows[0];
  console.log('\n📈 Import Summary:');
  console.log(`Total Records: ${s.total_records}`);
  console.log(`Unique Salons: ${s.unique_salons}`);
  console.log(`Unique Phones: ${s.unique_phones}`);
  console.log(`Countries/States: ${s.countries}`);
  console.log(`Cities: ${s.cities}`);
  console.log(`Total Profiles: ${s.total_profiles}`);
  console.log(`On Latest Version (1021): ${s.on_latest_version}`);
}

async function main() {
  const connectionString = process.env.NEON_DATABASE_URL || process.env.DATABASE_URL;
  
  if (!connectionString) {
    console.error('❌ NEON_DATABASE_URL or DATABASE_URL not set');
    process.exit(1);
  }
  
  const client = new Client({ connectionString });
  
  try {
    await client.connect();
    console.log('🔗 Connected to database');
    
    await runMigration(client);
    await importData(client);
    
    console.log('\n🎉 All done!');
  } catch (error) {
    console.error('❌ Error:', error.message);
    process.exit(1);
  } finally {
    await client.end();
  }
}

if (require.main === module) {
  main();
}

module.exports = {
  rawSalonUsers,
  salonUsers,
  cleaningReport,
};
